const lead = $input.item.json;
const email = lead.email || lead.company_url || '';
let domain = '';

if (email.includes('@')) {
  domain = email.split('@')[1];
} else if (email.startsWith('http')) {
  try {
    domain = new URL(email).hostname.replace('www.', '');
  } catch (e) {
    domain = email;
  }
} else {
  domain = email;
}

const freeProviders = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com'];
const isBusinessEmail = domain && !freeProviders.includes(domain.toLowerCase());

return { 
  ...lead, 
  extracted_domain: domain,
  is_business: isBusinessEmail
};

const lead = $("Extract Domain").item.json;
const clayData = $input.item.json;

// Clay usually returns deep enriched data including company info, description, and AI insights if configured
return {
  ...lead,
  company_name: clayData.company?.name || lead.company_name || lead.businessName,
  company_domain: clayData.company?.domain || lead.extracted_domain,
  company_logo: clayData.company?.logoUrl || null,
  ai_research: clayData.ai_summary || clayData.company?.description || 'Enriched via Clay AI',
  enrichment_source: 'clay_official',
  enriched_at: new Date().toISOString(),
  status: 'enriched'
};
